import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Validate input length to prevent buffer overflow
        int maxLength = 10;
        if (name.length() > maxLength) {
            System.out.println("Input exceeds maximum length of " + maxLength + " characters.");
            return;
        }

        // Safe code - using StringBuilder instead of fixed-size array
        StringBuilder buffer = new StringBuilder(name.substring(0, Math.min(name.length(), maxLength)));

        System.out.println("Welcome, " + buffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
